    const email = builder.createString(data.fields.email);
    const relationIds_orders = Array.isArray(data.relationIds.orders) ? data.relationIds.orders : [data.relationIds.orders];
    const ordersVector = Customer.createOrdersIdsVector(builder, relationIds_orders.map(id => builder.createString(id)));
    const relationIds_cart = Array.isArray(data.relationIds.cart) ? data.relationIds.cart : [data.relationIds.cart];
    const cartVector = Customer.createCartIdsVector(builder, relationIds_cart.map(id => builder.createString(id)));
